module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const xmin = Number.isFinite(parseFloat(args.xmin)) ? parseFloat(args.xmin) : -5;
const xmax = Number.isFinite(parseFloat(args.xmax)) ? parseFloat(args.xmax) : 5;
const showAxis = String(args.axis) !== 'false';
const legendOn = String(args.legend) !== 'false';
const sw = Math.max(0.3, Math.min(5, Number.isFinite(parseFloat(args.strokewidth)) ? parseFloat(args.strokewidth) : 1.3));
const palette = ['#2563eb', '#dc2626', '#16a34a', '#9333ea', '#ea580c', '#0891b2'];
const W = 160, PAD = 2, N = 200;
const H = Math.max(40, Math.min(240, Number.isFinite(parseFloat(args.height)) ? parseFloat(args.height) : 100));
const funcs = [];
sections.map((s) => (s || '').trim()).filter(Boolean).forEach((s) => {
  const i = s.indexOf('|');
  const expr = (i >= 0 ? s.slice(0, i) : s).trim();
  const label = i >= 0 ? s.slice(i + 1).trim() : '';
  if (!/^[\w+\-*/().,^\s]*$/.test(expr)) return; // reject anything beyond math chars
  let fn = null;
  try { fn = new Function('x', 'with(Math){return (' + expr.replace(/\^/g, '**') + ');}'); fn(0); } catch (e) { fn = null; }
  if (fn) funcs.push({ fn, label: label || expr });
});
if (!funcs.length) return `<div>(funcplot: one "expression | label" per section, e.g. sin(x))</div>`;
// sample
const series = funcs.map((f) => {
  const pts = [];
  for (let i = 0; i <= N; i++) {
    const x = xmin + (xmax - xmin) * i / N;
    let y; try { y = f.fn(x); } catch (e) { y = NaN; }
    pts.push([x, typeof y === 'number' && Number.isFinite(y) ? y : NaN]);
  }
  return pts;
});
const ys = series.flat().map((p) => p[1]).filter(Number.isFinite);
let ylo = args.ymin !== '' && args.ymin != null ? parseFloat(args.ymin) : Math.min(...ys);
let yhi = args.ymax !== '' && args.ymax != null ? parseFloat(args.ymax) : Math.max(...ys);
if (!Number.isFinite(ylo)) ylo = -1; if (!Number.isFinite(yhi)) yhi = 1;
if (yhi === ylo) { yhi += 1; ylo -= 1; }
const pad = (yhi - ylo) * 0.06; ylo -= pad; yhi += pad;
const gx = (x) => PAD + ((x - xmin) / (xmax - xmin)) * (W - 2 * PAD);
const gy = (y) => H - PAD - ((y - ylo) / (yhi - ylo)) * (H - 2 * PAD);
let svg = '';
if (String(args.grid) !== 'false') {
  const stepX = Math.pow(10, Math.floor(Math.log10((xmax - xmin) / 4)));
  const stepY = Math.pow(10, Math.floor(Math.log10((yhi - ylo) / 4)));
  for (let v = Math.ceil(xmin / stepX) * stepX; v <= xmax; v += stepX)
    svg += `<line x1="${gx(v).toFixed(1)}" y1="0" x2="${gx(v).toFixed(1)}" y2="${H}" class="mdp-fp-grid"/>`;
  for (let v = Math.ceil(ylo / stepY) * stepY; v <= yhi; v += stepY)
    svg += `<line x1="0" y1="${gy(v).toFixed(1)}" x2="${W}" y2="${gy(v).toFixed(1)}" class="mdp-fp-grid"/>`;
}
if (showAxis && ylo < 0 && yhi > 0) svg += `<line x1="0" y1="${gy(0).toFixed(1)}" x2="${W}" y2="${gy(0).toFixed(1)}" class="mdp-fp-axis"/>`;
if (showAxis && xmin < 0 && xmax > 0) svg += `<line x1="${gx(0).toFixed(1)}" y1="0" x2="${gx(0).toFixed(1)}" y2="${H}" class="mdp-fp-axis"/>`;
series.forEach((pts, si) => {
  const c = palette[si % palette.length];
  let d = '', pen = false;
  pts.forEach((p) => {
    if (!Number.isFinite(p[1]) || p[1] < ylo - (yhi - ylo) || p[1] > yhi + (yhi - ylo)) { pen = false; return; }
    d += (pen ? ' L' : ' M') + gx(p[0]).toFixed(1) + ',' + gy(Math.max(ylo, Math.min(yhi, p[1]))).toFixed(1);
    pen = true;
  });
  if (d) svg += `<path d="${d.trim()}" class="mdp-fp-curve" style="stroke:${c};"/>`;
});
let legend = '';
if (legendOn && (funcs.length > 1 || funcs[0].label !== '')) {
  legend = `<div class="mdp-fp-legend">` + funcs.map((f, i) =>
    `<span><i style="background:${palette[i % palette.length]};"></i>${esc(f.label)}</span>`).join('') + `</div>`;
}
return `\n\n<div class="mdp-mod-funcplot" style="--fp-sw:${sw};"><svg viewBox="0 0 ${W} ${H}" preserveAspectRatio="xMidYMid meet">${svg}</svg>${legend}</div>\n\n`;
